import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { WorkerService } from '../../Services/WorkerService';
import { WorkerModelDto } from '../../Models/WorkerModel';


@Component({
  selector: 'app-add-worker-comp',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './add-worker-comp.html',
  styleUrls: ['./add-worker-comp.scss']
})
export class AddWorkerComp {
  worker: Partial<WorkerModelDto> = {
    firstName: '',
    lastName: '',
    dateOfStart: '',
    birthday: '',
    position: 0, // יחושב מ־selectedPositions
    mine: 0 // Men
  };

  selectedPositions: number[] = []; // מערך לבחירות מרובות

  positionOptions = [
    { value: 1, label: 'Manager' }, // 2^0
    { value: 2, label: 'Developer' }, // 2^1
    { value: 4, label: 'Designer' }, // 2^2
    { value: 8, label: 'Tester' }, // 2^3
    { value: 16, label: 'Support' } // 2^4
  ];

  mineOptions = [
    { value: 0, label: 'Men' },
    { value: 1, label: 'Women' }
  ];

  constructor(private workerService: WorkerService, private router: Router) {}

  onSubmit(): void {
    // חשב position כ־bitwise OR
    this.worker.position = this.selectedPositions.reduce((acc, val) => acc | val, 0);
    this.workerService.addWorker(this.worker as WorkerModelDto).subscribe({
      next: () => this.router.navigate(['/workers']),
      error: () => alert('שגיאה בהוספת עובד')
    });
  }

  cancel(): void {
    this.router.navigate(['/workers']);
  }

  onPositionChange(value: number, checked: boolean): void {
    if (checked) {
      this.selectedPositions.push(value);
    } else {
      this.selectedPositions = this.selectedPositions.filter(p => p !== value);
    }
  }
}
<p>add-worker-comp works!</p>

<div class="add-worker">
  <h2>הוספת עובד</h2>

  <form (ngSubmit)="onSubmit()" #f="ngForm">
    <div>
      <label>First Name</label>
      <input name="firstName" [(ngModel)]="worker.firstName" required />
    </div>

    <div>
      <label>Last Name</label>
      <input name="lastName" [(ngModel)]="worker.lastName" required />
    </div>

    <div>
      <label>Start Date</label>
      <input name="dateOfStart"  [(ngModel)]="worker.dateOfStart" required />
    </div>

    <div>
      <label>Birthday</label>
      <input name="birthday" [(ngModel)]="worker.birthday" required />
    </div>

    <div>
      <label>Position (בחר אחד או יותר)</label>
      <div *ngFor="let opt of positionOptions">
        <input type="checkbox" [value]="opt.value" (change)="onPositionChange(opt.value, $event.target.checked)" />
        {{ opt.label }}
      </div>
    </div>

    <div>
      <label>Mine</label>
      <select name="mine" [(ngModel)]="worker.mine">
        <option *ngFor="let opt of mineOptions" [value]="opt.value">{{ opt.label }}</option>
      </select>
    </div>

    <button type="submit">שמור</button>
    <button type="button" (click)="cancel()">ביטול</button>
  </form>
</div>
